{
  "verses": [
    {
      "n": 7,
      "column": "left",
      "text": "Djeedajt tain KUNgam\nweens par ohtru ar Teifschann/\nteizeet muhfu Deewu ar Kohl-\nlehm.\n"
    },
    {
      "n": 8,
      "column": "left",
      "text": "Kas to Debbezi ar Vadeb-\nbefim apflahj/ kas Leetus dohd\npreckich Semmes/ kas leek Sah-\nli augt us Kalneem.\n"
    },
    {
      "n": 9,
      "column": "left",
      "text": "Kas Lohpeem Barribu\ndohd/ teem jauneem Kraukteem/\nkad tee fauz.\n"
    },
    {
      "n": 10,
      "column": "left",
      "text": "Wiꞥſcham ne irr labs\nBrahts pee ta Sirga Stipru-\nma/ wiꞥſcham ne patihk to Wiht-\ntu Leeli.\n"
    },
    {
      "n": 11,
      "column": "left",
      "text": "Tam KUNGAM pa-\ntihk tee/ kas winnu bihstahs/ kas\nus winna Schehlastibu gaida.\n"
    },
    {
      "n": 12,
      "column": "left",
      "text": "Teiz Jerusaleme to KUN-\nGU/ slawe Zianna tauu Deewn.\n"
    },
    {
      "n": 13,
      "column": "left",
      "text": "Jo wiꞥſch stiprina tauu\nWahrtu Klinkus/ wiꞥſch tweh-\nti tauus Behrmus eekſch tewis.\n"
    },
    {
      "n": 14,
      "column": "left",
      "text": "Wiꞥſch eedohd tawahn\nRohbeschahm Meern/ wiꞥſch\npee-ehdna tew ar breedufcheem\nRweefcheem.\n"
    },
    {
      "n": 15,
      "column": "left",
      "text": "Wiꞥſch fuhta farwas Ap-\nschischanas wirs Semmes/\nwinna Wahrs teek ar Steig-\nchann.\n"
    },
    {
      "n": 16,
      "column": "left",
      "text": "Wiꞥſch dehd Sneegu ka\nWillu/ wiꞥſch kaifa Saluu ka\nPeluus.\n"
    },
    {
      "n": 17,
      "column": "left",
      "text": "Wiꞥſch mett farwu Krussu\nka Rummofus/ kas warr pastah-\nweht preckich winna Aufkuma.\n"
    },
    {
      "n": 18,
      "column": "right",
      "text": "Wiꞥſch fuhta far\nWahrdu/ un leek to iſku-\nwiꞥſch leek farwu Wehju pub-\ntee Uhdezi noteek.\n"
    },
    {
      "n": 19,
      "column": "right",
      "text": "Un stahsta Jehkabain\nwn Wahrdu/ Israëtam farw-\nEikfumus un Teefas.\n"
    },
    {
      "n": 20,
      "column": "right",
      "text": "Ta ne darra wiꞥſch\nkahdeein Paganeein/ nedg le-\nteem finnaht jawas Teefas/ D\nleluja.\n"
    }
  ],
  "confidence": "high",
  "notes": ""
}
